// ============================================
// PARSER ULTRA ROBUSTO PARA RESPOND TO WEBHOOK
// ============================================
// Genera la respuesta que Retell AI recibirá
// de cada herramienta de Google Calendar
// Maneja TODOS los formatos posibles del agente
// ============================================

// ============================================
// 1. OBTENER OUTPUT DEL AGENTE (ULTRA ROBUSTO)
// ============================================

let rawOutput = $input.all()[0].json;

// CASO 1: Si viene en { output: "..." }
if (rawOutput.output) {
  rawOutput = rawOutput.output;
}

// CASO 2: Si viene en { body: { output: "..." } }
else if (rawOutput.body && rawOutput.body.output) {
  rawOutput = rawOutput.body.output;
}

// CASO 3: Si es un array [{ output: "..." }]
else if (Array.isArray(rawOutput)) {
  rawOutput = rawOutput[0];
  if (rawOutput && rawOutput.output) {
    rawOutput = rawOutput.output;
  }
}

// CASO 4: Si viene en { data: { output: "..." } }
else if (rawOutput.data && rawOutput.data.output) {
  rawOutput = rawOutput.data.output;
}

// CASO 5: Si viene en { json: { output: "..." } }
else if (rawOutput.json && rawOutput.json.output) {
  rawOutput = rawOutput.json.output;
}

// ============================================
// 2. LIMPIAR Y PARSEAR (ULTRA ROBUSTO)
// ============================================

function limpiarYParsear(output) {
  if (!output) return null;

  let limpio = output;

  // Si es un array, tomar el primer elemento
  if (Array.isArray(limpio)) {
    limpio = limpio[0] || "";
  }

  // Si es un objeto con propiedad 'output'
  if (typeof limpio === 'object' && limpio !== null && limpio.output) {
    limpio = limpio.output;
  }

  // Si es un objeto con propiedad 'body'
  if (typeof limpio === 'object' && limpio !== null && limpio.body) {
    limpio = limpio.body;
  }

  // Si ya es un objeto con la estructura esperada, devolverlo directamente
  if (typeof limpio === 'object' && limpio !== null && 
      limpio.campos_originales && 
      limpio.herramienta_ejecutada && 
      limpio.estado_ejecucion !== undefined) {
    return limpio;
  }

  // Convertir objeto a string si es necesario
  if (typeof limpio === 'object' && limpio !== null) {
    limpio = JSON.stringify(limpio);
  }

  // Asegurar que es string
  limpio = String(limpio).trim();

  // Limpiar markdown
  limpio = limpio
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/g, '')
    .replace(/^json\s*/i, '')
    .trim();

  // Si está escapado como string "{\n  \"key\": ...}"
  if (limpio.startsWith('"') && limpio.endsWith('"')) {
    try {
      limpio = JSON.parse(limpio);
      // Si después de parsear sigue siendo string, limpiar caracteres de escape
      if (typeof limpio === 'string') {
        limpio = limpio.replace(/\\n/g, '\n').replace(/\\"/g, '"');
      }
    } catch (e) {
      // Si falla, solo remover las comillas externas
      limpio = limpio.slice(1, -1).replace(/\\n/g, '\n').replace(/\\"/g, '"');
    }
  }

  // Parsear a JSON si es string
  if (typeof limpio === 'string') {
    try {
      return JSON.parse(limpio);
    } catch (e) {
      throw new Error(`No se pudo parsear el JSON: ${e.message}`);
    }
  }

  return limpio;
}

let agentData;

try {
  agentData = limpiarYParsear(rawOutput);

  if (!agentData) {
    throw new Error('No se pudo obtener datos del agente');
  }
} catch (parseError) {
  // Si falla todo, devolver error
  return {
    success: false,
    action: 'error_parsing',
    error: parseError.message,
    mensaje: 'Error al procesar la respuesta del agente',
    debug_info: {
      tipo_input: typeof rawOutput,
      es_array: Array.isArray(rawOutput),
      preview: typeof rawOutput === 'string' 
        ? rawOutput.substring(0, 200) 
        : JSON.stringify(rawOutput).substring(0, 200)
    }
  };
}

// ============================================
// 3. EXTRAER DATOS BÁSICOS
// ============================================

const accion = agentData.campos_originales?.accion || agentData.herramienta_ejecutada || 'unknown';
const exitoso = agentData.estado_ejecucion === 'exitoso';
const respuestaHerramienta = agentData.respuesta_herramienta || {};

// ============================================
// 4. TABLA DE ZONAS HORARIAS
// ============================================

const ZONAS_HORARIAS = {
  // GMT-6 (mismo horario que México)
  'México': 0,
  'Mexico': 0,
  'Costa Rica': 0,
  'Guatemala': 0,
  'Panamá': 0,
  'Panama': 0,
  'El Salvador': 0,
  'Honduras': 0,
  'Nicaragua': 0,

  // GMT-5 (1 hora adelante de México)
  'Colombia': -1,
  'Perú': -1,
  'Peru': -1,
  'Ecuador': -1,
  'USA Este': -1,
  'Estados Unidos Este': -1,

  // GMT-4 (2 horas adelante de México)
  'Venezuela': -2,

  // GMT-3 (3 horas adelante de México)
  'Argentina': -3,
  'Chile': -3,
  'Brasil': -3,
  'Brazil': -3,

  // GMT+1 (7 horas adelante de México)
  'España': -7,
  'Espana': -7,

  // GMT-8 (2 horas atrás de México)
  'USA Pacífico': 2,
  'USA Pacifico': 2,
  'Estados Unidos Pacífico': 2,
  'Estados Unidos Pacifico': 2
};

// ============================================
// 5. FUNCIÓN: Obtener diferencia horaria
// ============================================

function obtenerDiferenciaHoraria(pais) {
  if (!pais || pais === 'sin_dato') return 0;

  // Normalizar el país (eliminar tildes, mayúsculas)
  const paisNormalizado = pais.trim();

  // Buscar coincidencia exacta primero
  if (ZONAS_HORARIAS.hasOwnProperty(paisNormalizado)) {
    return ZONAS_HORARIAS[paisNormalizado];
  }

  // Buscar coincidencia parcial (case insensitive)
  const paisLower = paisNormalizado.toLowerCase();
  for (const [key, value] of Object.entries(ZONAS_HORARIAS)) {
    if (key.toLowerCase() === paisLower) {
      return value;
    }
  }

  // Si no se encuentra, asumir mismo horario que México
  return 0;
}

// ============================================
// 6. FUNCIÓN: Formatear fecha legible
// ============================================

function formatearFecha(isoDate, ajusteHoras = 0) {
  if (!isoDate || isoDate === 'null' || isoDate === 'sin_dato') return 'sin_dato';

  try {
    const date = new Date(isoDate);

    if (isNaN(date.getTime())) return 'sin_dato';

    // Validar que esté en horario laboral (9 AM - 5 PM México)
    const horasMexico = date.getHours();
    if (horasMexico < 9 || horasMexico >= 17) {
      return 'fuera_de_horario';
    }

    // Aplicar ajuste de zona horaria
    const dateAjustada = new Date(date);
    dateAjustada.setHours(dateAjustada.getHours() + ajusteHoras);

    const dias = ['Domingo', 'Lunes', 'Martes', 'Miércoles', 'Jueves', 'Viernes', 'Sábado'];
    const meses = ['enero', 'febrero', 'marzo', 'abril', 'mayo', 'junio', 
                   'julio', 'agosto', 'septiembre', 'octubre', 'noviembre', 'diciembre'];

    const dia = dateAjustada.getDate();
    const mes = meses[dateAjustada.getMonth()];
    const año = dateAjustada.getFullYear();
    const horas = dateAjustada.getHours();
    const minutos = dateAjustada.getMinutes().toString().padStart(2, '0');
    const ampm = horas >= 12 ? 'PM' : 'AM';
    const horas12 = horas % 12 || 12;

    return `${dias[dateAjustada.getDay()]} ${dia} de ${mes} de ${año} a las ${horas12}:${minutos} ${ampm}`;
  } catch {
    return 'sin_dato';
  }
}

// ============================================
// 7. GENERAR RESPUESTA SEGÚN ACCIÓN
// ============================================

let response = {};

try {

  if (accion === 'agendar_cita' || accion === 'create_event') {

    // ============================================
    // RESPUESTA: AGENDAR CITA
    // ============================================

    if (exitoso && respuestaHerramienta.id) {

      const meetLink = respuestaHerramienta.hangoutLink || 
                       respuestaHerramienta.conferenceData?.entryPoints?.find(ep => ep.entryPointType === 'video')?.uri || 
                       'sin_dato';

      response = {
        success: true,
        action: 'cita_agendada',
        event_id: respuestaHerramienta.id,
        meet_link: meetLink,
        calendar_link: respuestaHerramienta.htmlLink || 'sin_dato',

        // CAMPOS DE FECHA
        fecha_cita_original: agentData.campos_originales?.start_datetime || 'sin_dato',
        fecha_cita_mx: agentData.campos_normalizados?.fecha_cita_mx || 'sin_dato',
        fecha_cita_cliente: agentData.campos_normalizados?.fecha_cita_zonahoraria_cliente || 'sin_dato',
        fecha_cita_legible_cliente: agentData.campos_normalizados?.fecha_cita_zonahoraria_cliente_legible || 'sin_dato',

        // DATOS DEL CLIENTE (NUEVO)
        nombre_cliente: agentData.campos_originales?.nombre_cliente || 'sin_dato',
        email_cliente: agentData.campos_originales?.attendee_email || 'sin_dato',
        telefono_cliente: agentData.campos_originales?.telefono_cliente || agentData.campos_normalizados?.telefono_normalizado || 'sin_dato',
        pais_cliente: agentData.campos_originales?.pais_cliente || 'sin_dato',
        empresa_cliente: agentData.campos_originales?.empresa_cliente || 'sin_dato',
        servicio_interes: agentData.campos_originales?.servicio_interes || 'sin_dato',

        duracion_minutos: 30,
        mensaje: `Cita agendada exitosamente para el ${agentData.campos_normalizados?.fecha_cita_zonahoraria_cliente_legible || formatearFecha(agentData.campos_normalizados?.fecha_cita_zonahoraria_cliente)}`
      };

    } else {

      response = {
        success: false,
        action: 'cita_agendada',
        error: agentData.mensaje || 'No se pudo agendar la cita',
        mensaje: agentData.mensaje || 'Error al crear el evento en Google Calendar'
      };

    }

  } else if (accion === 'cancelar_cita' || accion === 'delete_event') {

    // ============================================
    // RESPUESTA: CANCELAR CITA
    // ============================================

    if (exitoso) {

      response = {
        success: true,
        action: 'cita_cancelada',
        event_id: agentData.campos_originales?.event_id || 'sin_dato',
        motivo: agentData.campos_originales?.motivo || 'Sin motivo especificado',
        mensaje: 'Cita cancelada exitosamente'
      };

    } else {

      response = {
        success: false,
        action: 'cita_cancelada',
        error: agentData.mensaje || 'No se pudo cancelar la cita',
        mensaje: agentData.mensaje || 'Error al eliminar el evento del calendario'
      };

    }

  } else if (accion === 'disponibilidad' || accion === 'buscar_cita' || accion === 'getall_events'|| accion === 'getall_event1') {

    // ============================================
    // RESPUESTA: CONSULTAR DISPONIBILIDAD
    // ============================================

    if (exitoso && respuestaHerramienta.items) {

      // Obtener país del cliente desde campos_originales
      const paisCliente = agentData.campos_originales?.pais_cliente || 
                          agentData.campos_originales?.pais || 
                          'México';

      const diferenciaHoraria = obtenerDiferenciaHoraria(paisCliente);

      // Procesar eventos ocupados
      const eventosOcupados = respuestaHerramienta.items
        .filter(item => item.start && item.start.dateTime) // Solo eventos con hora específica
        .map(item => ({
          start: item.start.dateTime,
          end: item.end.dateTime,
          start_legible_mx: formatearFecha(item.start.dateTime, 0),
          start_legible_cliente: formatearFecha(item.start.dateTime, diferenciaHoraria),
          summary: item.summary || 'Evento sin título'
        }));

      // Generar slots disponibles (9 AM - 4:30 PM, cada 30 min)
      const after = new Date(agentData.campos_originales?.After);
      const before = new Date(agentData.campos_originales?.Before);
      const slotsDisponibles = [];

      // Validar fechas
      if (!isNaN(after.getTime()) && !isNaN(before.getTime())) {

        // Iterar por cada día en el rango
        let currentDate = new Date(after);
        while (currentDate <= before) {

          // Solo días laborales (lunes a viernes)
          const diaSemana = currentDate.getDay();
          if (diaSemana >= 1 && diaSemana <= 5) {

            // Generar slots de 9 AM a 4:30 PM (último slot termina a las 5 PM)
            for (let hora = 9; hora <= 16; hora++) {
              const minutosMaximos = (hora === 16) ? 30 : 60;
              for (let minuto = 0; minuto < minutosMaximos; minuto += 30) {

                const slotStart = new Date(currentDate);
                slotStart.setHours(hora, minuto, 0, 0);

                const slotEnd = new Date(slotStart);
                slotEnd.setMinutes(slotEnd.getMinutes() + 30);

                // Verificar si el slot está dentro del rango solicitado
                if (slotStart >= after && slotEnd <= before) {

                  // Verificar si el slot NO está ocupado
                  const estaOcupado = eventosOcupados.some(evento => {
                    const eventoStart = new Date(evento.start);
                    const eventoEnd = new Date(evento.end);
                    return (slotStart >= eventoStart && slotStart < eventoEnd) ||
                           (slotEnd > eventoStart && slotEnd <= eventoEnd) ||
                           (slotStart <= eventoStart && slotEnd >= eventoEnd);
                  });

                  if (!estaOcupado) {
                    // Formatear para hora de México y hora del cliente
                    const fechaLegibleMx = formatearFecha(slotStart, 0);
                    const fechaLegibleCliente = formatearFecha(slotStart, diferenciaHoraria);

                    // Solo agregar si ambas fechas son válidas
                    if (fechaLegibleMx !== 'sin_dato' && 
                        fechaLegibleMx !== 'fuera_de_horario' &&
                        fechaLegibleCliente !== 'sin_dato' &&
                        fechaLegibleCliente !== 'fuera_de_horario') {

                      slotsDisponibles.push({
                        start: slotStart.toISOString().replace('Z', '-06:00'),
                        start_legible_mx: fechaLegibleMx,
                        start_legible_cliente: fechaLegibleCliente,
                        pais_cliente: paisCliente,
                        diferencia_horaria: diferenciaHoraria
                      });
                    }
                  }

                }
              }
            }
          }

          // Avanzar al siguiente día
          currentDate.setDate(currentDate.getDate() + 1);
          currentDate.setHours(0, 0, 0, 0);
        }
      }

      response = {
        success: true,
        action: 'disponibilidad_consultada',
        total_disponibles: slotsDisponibles.length,
        total_ocupados: eventosOcupados.length,
        slots_disponibles: slotsDisponibles,
        slots_ocupados: eventosOcupados,
        pais_cliente: paisCliente,
        diferencia_horaria: diferenciaHoraria,
        mensaje: `Se encontraron ${slotsDisponibles.length} horarios disponibles`
      };

    } else {

      response = {
        success: false,
        action: 'disponibilidad_consultada',
        error: agentData.mensaje || 'No se pudo consultar la disponibilidad',
        mensaje: agentData.mensaje || 'Error al consultar el calendario'
      };

    }

  } else {

    // ============================================
    // RESPUESTA: ACCIÓN DESCONOCIDA
    // ============================================

    response = {
      success: false,
      action: 'unknown',
      error: 'Acción no reconocida',
      mensaje: `La acción '${accion}' no es válida`
    };

  }

} catch (error) {

  // ============================================
  // RESPUESTA: ERROR EN PROCESAMIENTO
  // ============================================

  response = {
    success: false,
    action: 'error_procesamiento',
    error: error.message,
    error_stack: error.stack,
    mensaje: 'Error al procesar la respuesta del agente',
    debug_info: {
      accion_detectada: accion,
      exitoso: exitoso,
      tiene_respuesta_herramienta: !!respuestaHerramienta,
      tipo_respuesta_herramienta: typeof respuestaHerramienta
    }
  };

}

// ============================================
// 8. RETORNAR RESPUESTA
// ============================================
return response;

